import requests

def fetch_extended_hours_data(api_url, stock_symbol):
    """
    Fetches pre-market and after-hours trading data for a given stock symbol.
    Assumes an API endpoint that returns JSON data.
    """
    params = {
        'symbol': stock_symbol,
        'session': 'extended'
    }
    response = requests.get(api_url, params=params)
    if response.status_code == 200:
        return response.json()
    else:
        raise Exception(f"Failed to fetch data: {response.status_code}")

